var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"손님을 초대할 때는 얼굴을 마주하라고 가르치지 않았나요?","JPN":"お客様を招待した際は顔を合わせてお出迎えするようにと教えたはずです。","ENG":"Have I not taught you to present yourself visibly when greeting a guest?","TWN":"我記得我教過你，招待客人時要親自迎接才是。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이제 와서 도망칠 생각은 없습니다. 어서 나오시죠.","JPN":"ここまで来て逃げるつもりはありません。出てきてください。","ENG":"I have no intention to flee at this point. Show yourself.","TWN":"我既然來了，就沒想過要逃走，快出來吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"실례를 저질렀네요.","JPN":"失礼しました。","ENG":"That was rude of me.","TWN":"真是失禮了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"하지만 이것도 당신이 너무 느릿느릿 움직인 탓 아닐까요?","JPN":"ですが、これもあなたがあまりにものんびりしていたせいですよ？","ENG":"But this is all because you've been moving far too slowly.","TWN":"不過，還不是因為你動作太慢？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"너무 늦으시는 것 같아서 기껏 고용한 용병들도 해산시키려던 참이었거든요.","JPN":"あまりにも遅いから、せっかく雇った傭兵も解散させようとしていたところです。","ENG":"I was about to dismiss the mercenaries I went through the trouble of hiring because you were running so late.","TWN":"慢到我差點就要把雇傭的傭兵都給解散了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 결과적으로 이렇게 무사히 도착했죠.","JPN":"しかし、結果的にはこのように無事到着しました。","ENG":"But ultimately, here I am, in one piece.","TWN":"我這不是來了嗎。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"당신에게는 아쉽겠네요. 제 발을 묶기 위해 한 준비들이 다 소용없게 되어 버려서.","JPN":"残念ですね。私を足止めしようと用意したものが全部無駄になってしまって。","ENG":"You must be disappointed, given how all your preparation to pin me down has been rendered futile.","TWN":"你準備了這麼多，都沒能阻止我來到這裡，是不是感到很可惜。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"나쁜 솜씨는 아니었지만 여전히 마무리가 아쉬워요, 릴리.","JPN":"悪くありませんが相変わらず詰めが甘いです、リリー。","ENG":"That wasn't half bad, but as usual, your finishing touch was a bit lacking, Lily.","TWN":"雖然有長進，但收尾不怎麼樣，莉莉。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......전 당신이 나타나기만 기다리고 있었습니다. 무슨 말을 하는지 모르겠네요.","JPN":"……私はずっとあなたが現れるのを待っていました。何を言っているのか分かりませんね。","ENG":"I was actually waiting for you to appear. I have no idea what you're talking about.","TWN":"……我一直在等你到來，真不明白你在說什麼。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......?","JPN":"……？","ENG":"......?","TWN":"……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"리코리스, 그 꼬마를 끌고 와요.","JPN":"リコリス、あのチビを連れてきてください。","ENG":"Bring me the girl, Lycoris.","TWN":"莉克麗絲，把那個小孩子帶過來。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"네, 네. 여기 대령했어.","JPN":"はいはい、ここにいるよ。","ENG":"Yeah, yeah. Here she is.","TWN":"是，是。我帶來了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"메, 메이드장님! 제성함다......! 많이 안 다치셨슴까?!","JPN":"メ、メイド長！　申し訳ないっす！　怪我は大丈夫っすか？","ENG":"C-Chief Maid! I'm so sorry, ma'am! Have they hurt you?","TWN":"女、女僕長大人！對不起……！你沒受傷吧？！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"걱정해 줘서 고마워요, 모네. 보다시피 저는 무사해요.","JPN":"心配かけましたね、モネ。ありがとうございます、私は無事です。","ENG":"Thank you for your concerns, Mone. As you can see, I'm perfectly fine.","TWN":"謝謝你的關心，莫妮。如你所見，我沒事。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"기억을 잃었다더니 하는 짓은 더 가증스러워졌네요.","JPN":"記憶を失ったとはいえ、その善人ぶりは見てられませんね。","ENG":"Your amnesia has made you even more detestable.","TWN":"我聽說你失憶了，可你的一舉一動變得更加令人厭惡。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"저한테는 항상 메이드답게 굴라고 입 한 번 마음대로 뻥긋 못 하게 다그치던 주제에......","JPN":"私にはいつもメイドらしく、無駄口を叩かないようにと叱っていたくせに……","ENG":"You were always so strict with me, telling me that a maid should watch her every move and word...","TWN":"之前你一直讓我盡好女僕的本分，不讓我有一絲懈怠……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이 꼬마가...... 대체 뭐라고 그렇게 애지중지하는 거죠?","JPN":"このチビのことを……なぜそんなに大事にするのですか？","ENG":"And yet you indulge this child like this... Who is she to you?","TWN":"這個小孩子……你為什麼這麼在乎她？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......믿기 어렵겠지만, 저는 당신을 아꼈어요. 릴리.","JPN":"……信じられないと思いますが、私はあなたのことを大切にしていました、リリー。","ENG":"I know it may be hard to believe, but I was very fond of you, Lily.","TWN":"……雖然難以置信，但我也曾非常在乎你，莉莉。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"수술을 받을 때 떠오른 기억으로 알 수 있었습니다.","JPN":"手術を受ける時に思い出しました。","ENG":"I recovered some of my memories while I was undergoing surgery.","TWN":"我手術的時候浮現出了一些記憶。"},"stage":{"bg":"SS_MAID_01","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"맨션에 있는 동안 제가 저질렀던 잘못들......","JPN":"マンションにいる間、私が犯した過ち……","ENG":"About the atrocities I committed while I was at the Mansion...","TWN":"想起了那些我在曼森時犯下的錯誤……"},"stage":{"bg":"SS_MAID_01","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그리고 제가 맡아 기른 꽃들 중에 가장 빼어났던 당신에 대해서도.","JPN":"そして私が引き受けて育てた花の中で、最も優れていたあなたのことも。","ENG":"And about you, the finest flower that I raised.","TWN":"以及我替主人養育的花中最優秀的你。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 저는 그때, 당신이 그저 마스터의 마음에 드는 꽃이 되길 바랐다고만 오해했어요.","JPN":"しかし私はその時、\\nあなたがただマスターのお気に入りの花になりたいと望んでいるのだと誤解していました。","ENG":"But at the time, I mistakenly thought all you wanted was to become a flower that the Master found satisfactory.","TWN":"但當時我誤會了你，我以為你只是想成為讓主人滿意的那一朵花。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그래서 그 마음을 이룰 수 있도록 당신을 도왔지만......","JPN":"だからその望みが叶えられるよう、あなたに助力していましたが……","ENG":"That's why I helped you reach that goal, but...","TWN":"為了實現你的願望，我盡全力幫助你……"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"역겨운 소리 집어치우세요. 배신자.","JPN":"そんな戯言は吐き気がするのでやめてください、裏切り者。","ENG":"Enough with your foul lies, traitor.","TWN":"你的話讓我噁心，叛徒。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L45_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그런 말을 해 봐야 마스터를......","JPN":"そんなことを言ってもマスターを……","ENG":"No matter what you say, I'll never forgive you for betraying the Master...","TWN":"無論你說什麼，我都不會原諒背叛主人……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"아니! 절 배신한 당신을 용서할 생각 따윈 전혀 없습니다!","JPN":"いいえ、私を裏切ったあなたを許すつもりはまったくありません！","ENG":"Or rather, for betraying me!","TWN":"不！背叛我的你！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"릴리......","JPN":"リリー……","ENG":"Lily...","TWN":"莉莉……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이 자리에서, 이 꼬마의 눈앞에서 솎아내 드리겠습니다.","JPN":"この場で、このチビの目の前で間引いてやりましょう。","ENG":"I will pluck you out right here, in front of this child.","TWN":"我要在這個地方，在這個小孩子面前除掉你。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그럼 당신도 자신이 저지른 일이 얼마나 큰 죄인지 조금은 깨달을 수 있게 되겠죠.","JPN":"そうすれば、あなたも自分が犯したことがどれほど重い罪なのか少しはわかるでしょう。","ENG":"That way, you just might gain a modicum of insight on the gravity of your crimes.","TWN":"只有這樣你才會明白，你犯下了多麼嚴重的罪。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......그러지 말아요, 릴리.","JPN":"……おやめなさい、リリー。","ENG":"Please don't do that, Lily.","TWN":"……不要，莉莉。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"당신은 그렇게 나쁜 사람이 아닙니다. 지금이라도 마음을 돌려요.","JPN":"あなたは悪人ではありません。まだ間に合います。","ENG":"You are not such a bad person. It's not too late to change your mind.","TWN":"我知道你不是壞人，現在回心轉意還來得及。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"한 번 손을 더럽히면...... 저처럼 돌이킬 수 없으니까요.","JPN":"一度手を汚してしまえば……私のように取り返しがつかなくなります。","ENG":"Once you soil your hands... it will be too late, as it was with me.","TWN":"一旦弄髒了你的手……就會像我一樣無法回頭了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그래요. 그렇게 위선자 같은 소리나 하면서 주인님이 내린 명령도 거역했겠죠.","JPN":"そうですね。そうやって偽善者ぶってご主人様の命令に逆らったのでしょう。","ENG":"Yes, I'm sure that's what you said when you defied the Master's orders, hypocrite.","TWN":"你就是用那種虛偽的言語抗拒了主人的命令吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"전원, 사격 준비.","JPN":"全員、射撃準備を。","ENG":"Everyone, get ready to fire.","TWN":"全員，準備射擊。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"메, 메이드장님! 어서 피하셔야 함다!!","JPN":"メ、メイド長！　はやく逃げてくださいっす！","ENG":"C-Chief Maid! You have to get out of here, ma'am!","TWN":"女、女僕長大人！你快跑啊！！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"저 자를...... 확실하게 처리하세요!","JPN":"あの者を……確実に始末してください！","ENG":"Take her down... no matter what!","TWN":"一定要……除掉她！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};